content.content:
1	/**
2	 * Astrolabe — public types.
3	 *
4	 * PlanDoc, ScopeItem, Decision, and supporting types for the brief-to-spec
5	 * planning pipeline.
6	 */
7	
8	// ── Plan status ──────────────────────────────────────────────────────
9	
10	export type PlanStatus = 'reading' | 'analyzing' | 'reviewing' | 'writing' | 'completed' | 'failed';
11	
12	// ── Documents ────────────────────────────────────────────────────────
13	
14	export interface PlanDoc {
15	  [key: string]: unknown;
16	  /** The brief writ ID — primary key. */
17	  id: string;
18	  /** The codex this plan targets. */
19	  codex: string;
20	  /** Planning status. */
21	  status: PlanStatus;
22	
23	  // ── Reader output ───────────────────────────────────────────
24	  /** Codebase inventory: affected files, types, interfaces, patterns. */
25	  inventory?: string;
26	
27	  // ── Analyst output ──────────────────────────────────────────
28	  /** Analyst observations: refactoring opportunities, risks, conventions. */
29	  observations?: string;
30	  /** Scope items: what's in and what's out. */
31	  scope?: ScopeItem[];
32	  /** Architectural/design decisions with options. */
33	  decisions?: Decision[];
34	
35	  // ── Spec-writer output ──────────────────────────────────────
36	  /** The generated specification. */
37	  spec?: string;
38	  /** The writ ID of the generated mandate (or configured type). */
39	  generatedWritId?: string;
40	
41	  createdAt: string;
42	  updatedAt: string;
43	}
44	
45	export interface ScopeItem {
46	  id: string;
47	  description: string;
48	  rationale: string;
49	  included: boolean;
50	}
51	
52	export interface Decision {
53	  id: string;
54	  scope: string[];
55	  question: string;
56	  context?: string;
57	  options: Record<string, string>;
58	  recommendation?: string;
59	  rationale?: string;
60	  selected?: string;
61	  patronOverride?: string;
62	}
63	
64	// ── Filters ──────────────────────────────────────────────────────────
65	
66	export interface PlanFilters {
67	  /** Filter by status. */
68	  status?: PlanStatus;
69	  /** Filter by codex name. */
70	  codex?: string;
71	  /** Maximum number of results (default: 20). */
72	  limit?: number;
73	  /** Number of results to skip. */
74	  offset?: number;
75	}
76	
77	// ── Configuration ────────────────────────────────────────────────────
78	
79	export interface AstrolabeConfig {
80	  /** The writ type posted by the spec-writer engine. Default: 'mandate'. */
81	  generatedWritType?: string;
82	}
83	
84	declare module '@shardworks/nexus-core' {
85	  interface GuildConfig {
86	    astrolabe?: AstrolabeConfig;
87	  }
88	}
89	
90	// ── API ──────────────────────────────────────────────────────────────
91	
92	export interface AstrolabeApi {
93	  /** Show a plan by id. Throws if not found. */
94	  show(planId: string): Promise<PlanDoc>;
95	  /** List plans with optional filters, ordered by createdAt descending. */
96	  list(filters?: PlanFilters): Promise<PlanDoc[]>;
97	  /** Partially update a plan. Returns the updated document. Throws if not found. */
